/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
function solve(nums, target) {
    const n = nums.length;
    let minRemovals = Infinity;

    // The constraints are small enough (N <= 40) that iterating through all 2^N subsets is too slow (2^40).
    // However, we are looking for the *minimum* number of removals, which means maximizing the size of the remaining subset.
    // The number of elements is up to 40. A meet-in-the-middle approach might be appropriate if we were solving for existence,
    // but here we are optimizing based on subset size.

    // Since N <= 40, let's check if we can use dynamic programming or exhaustive search on smaller halves.
    // A direct search on subsets (2^N) is too slow.

    // Let's re-evaluate the complexity. N=40 suggests O(2^(N/2)) complexity (Meet-in-the-Middle).

    // Meet-in-the-Middle Approach:
    // Split nums into two halves: L (first n/2) and R (rest).
    const n1 = Math.floor(n / 2);
    const n2 = n - n1;

    // Map to store: {xor_sum: minimum_size_of_subset_to_achieve_this_xor}
    // For L: Map<XOR_L, min_size_L>
    const mapL = new Map();
    mapL.set(0, 0); // Empty set XOR is 0, size is 0

    // Generate all 2^n1 subsets for the left half
    for (let i = 1; i < (1 << n1); i++) {
        let currentXor = 0;
        let currentSize = 0;
        for (let j = 0; j < n1; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums[j];
                currentSize++;
            }
        }

        // We only store the minimum size required to achieve a specific XOR sum
        if (!mapL.has(currentXor) || currentSize < mapL.get(currentXor)) {
            mapL.set(currentXor, currentSize);
        }
    }

    // For R: List of all pairs: [xor_sum, size]
    const listR = [];
    listR.push([0, 0]); // Empty set XOR is 0, size is 0

    // Generate all 2^n2 subsets for the right half
    for (let i = 1; i < (1 << n2); i++) {
        let currentXor = 0;
        let currentSize = 0;
        for (let j = 0; j < n2; j++) {
            if ((i >> j) & 1) {
                currentXor ^= nums[n1 + j];
                currentSize++;
            }
        }
        listR.push([currentXor, currentSize]);
    }

    // Optimization: Since we only care about the *minimum* size, we can prune listR.
    // If we have two pairs (xor, size1) and (xor, size2) with size1 < size2, we only need (xor, size1).
    const mapR = new Map();
    for (const [xorR, sizeR] of listR) {
        if (!mapR.has(xorR) || sizeR < mapR.get(xorR)) {
            mapR.set(xorR, sizeR);
        }
    }

    // Now, iterate over all pairs (XOR_L, Size_L) from mapL and (XOR_R, Size_R) from mapR.
    // We need XOR_L ^ XOR_R = target, which means XOR_R = target ^ XOR_L.

    for (const [xorL, sizeL] of mapL.entries()) {
        const requiredXorR = target ^ xorL;

        if (mapR.has(requiredXorR)) {
            const sizeR = mapR.get(requiredXorR);
            const totalSize = sizeL + sizeR;

            // Minimum removals = Total elements - Maximum retained elements
            const removals = n - totalSize;

            if (removals < minRemovals) {
                minRemovals = removals;
            }
        }
    }

    if (minRemovals === Infinity) {
        return -1;
    } else {
        return minRemovals;
    }
}

